import{_ as t,o as a,c as d,ag as s}from"./chunks/framework.Nx1zvZTu.js";const g=JSON.parse('{"title":"WebSocket protocol","description":"","frontmatter":{},"headers":[],"relativePath":"reference/api/ws-protocol.md","filePath":"reference/api/ws-protocol.md"}'),i={name:"reference/api/ws-protocol.md"};function o(r,e,n,c,l,p){return a(),d("div",null,[...e[0]||(e[0]=[s('<h1 id="websocket-protocol" tabindex="-1">WebSocket protocol <a class="header-anchor" href="#websocket-protocol" aria-label="Permalink to &quot;WebSocket protocol&quot;">‚Äã</a></h1><p>Protocol version <strong>1.0</strong>. Served live and machine-readable at <code>GET /v1/protocol</code>.</p><p><strong>Transport</strong></p><ul><li><code>control_plane</code>: JSON text WebSocket frames (InterfaceMessage).</li><li><code>data_plane</code>: Raw binary WebSocket frames for chunk upload/read.</li><li><code>rest</code>: All non-WebSocket endpoints are described by /openapi.json.</li></ul><p><strong>Endpoints</strong></p><ul><li><code>/v1/interfaces/ws</code>: Create/attach any Interface; call/chunk/read/emit.</li><li><code>/v1/executions/ws</code>: Attach to an existing Execution by uuid.</li></ul><p><strong>Request headers</strong></p><table tabindex="0"><thead><tr><th>Header</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>X-Machinable-Project</code></td><td>no</td><td>Project directory to target (also ?project=); must be under the server&#39;s project_roots allowlist. Defaults to the launch project.</td></tr><tr><td><code>X-Machinable-User</code></td><td>no</td><td>Attributes created interfaces to this user (created_by). Defaults to the server&#39;s OS user.</td></tr><tr><td><code>X-Machinable-Python</code></td><td>no</td><td>Interpreter to serve the request (also ?python=); a non-gateway interpreter is routed to a subprocess worker.</td></tr><tr><td><code>Authorization</code></td><td>no</td><td>Bearer &lt;token&gt; when the server sets api_token.</td></tr></tbody></table><p><strong>Frames</strong></p><table tabindex="0"><thead><tr><th><code>type</code></th><th>Direction</th><th>Purpose</th></tr></thead><tbody><tr><td><code>connect</code></td><td>client‚Üíserver</td><td>Create or attach to an interface and bind the project.</td></tr><tr><td><code>connected</code></td><td>server‚Üíclient</td><td>Confirms the connection; returns uuid and resolved config.</td></tr><tr><td><code>call</code></td><td>client‚Üíserver</td><td>Invoke a public method on the connected interface.</td></tr><tr><td><code>result</code></td><td>server‚Üíclient</td><td>Single return value of a call.</td></tr><tr><td><code>stream</code></td><td>server‚Üíclient</td><td>One yielded value from a generator method; final=true closes.</td></tr><tr><td><code>event</code></td><td>server‚Üíclient</td><td>Unsolicited push from Interface.emit() (no call in flight).</td></tr><tr><td><code>error</code></td><td>server‚Üíclient</td><td>Failure detail; payload.code=&#39;not_found&#39; for missing reads.</td></tr><tr><td><code>chunk_start</code></td><td>client‚Üíserver</td><td>Begin a binary upload (write/append) or read (mode read).</td></tr><tr><td><code>chunk_end</code></td><td>client‚Üíserver</td><td>Finish the active upload (after one or more binary frames).</td></tr><tr><td><code>chunk_done</code></td><td>server‚Üíclient</td><td>Upload/read complete (bytes_written / bytes_sent).</td></tr><tr><td><code>widget_get</code></td><td>client‚Üíserver</td><td>Request a widget&#39;s full synced state.</td></tr><tr><td><code>widget_state</code></td><td>server‚Üíclient</td><td>A widget&#39;s full synced state (reply to widget_get).</td></tr><tr><td><code>widget_set</code></td><td>client‚Üíserver</td><td>Apply synced-state changes (model.set + save_changes).</td></tr><tr><td><code>widget_change</code></td><td>server‚Üíclient</td><td>Trait changes (reply to widget_set, or server-originated).</td></tr><tr><td><code>widget_msg</code></td><td>either</td><td>Custom widget message (model.send / msg:custom).</td></tr><tr><td><code>ping</code></td><td>client‚Üíserver</td><td>Liveness probe; answered with pong.</td></tr><tr><td><code>pong</code></td><td>server‚Üíclient</td><td>Reply to ping.</td></tr><tr><td><code>close</code></td><td>either</td><td>Teardown; the server evicts the interface from its cache.</td></tr></tbody></table><p><code>connect</code> fields:</p><ul><li><code>target</code> (string) (required): Module path to instantiate, or an existing uuid.</li><li><code>version</code> (array): Version list passed to Interface.make().</li><li><code>uuid</code> (string): Client-supplied id for create-by-id (content hash); idempotent in that the same id attaches to the existing instance.</li><li><code>label</code> (string): Optional mutable label to set on the instance.</li><li><code>project</code> (string): Project dir to bind (overrides header/query).</li><li><code>meta</code> (object): Client metadata stored with the interface.</li></ul><p><code>connected</code> fields:</p><ul><li><code>payload.uuid</code> (string): Interface uuid.</li><li><code>payload.config</code> (object): Resolved configuration.</li></ul><p><code>call</code> fields:</p><ul><li><code>method</code> (string) (required): Public method name (no leading underscore).</li><li><code>args</code> (array): Positional arguments.</li><li><code>kwargs</code> (object): Keyword arguments.</li></ul><p><code>result</code> fields:</p><ul><li><code>payload</code> (any): JSON-encoded result.</li></ul><p><code>stream</code> fields:</p><ul><li><code>payload</code> (any): One item; null on the terminal frame.</li></ul><p><code>event</code> fields:</p><ul><li><code>payload</code> (any): Emitted payload.</li></ul><p><code>error</code> fields:</p><ul><li><code>payload.message</code> (string): Message.</li><li><code>payload.code</code> (string): Typed code, e.g. &#39;not_found&#39; on a missing read.</li></ul><p><code>chunk_start</code> fields:</p><ul><li><code>id</code> (string) (required): Correlation id; must match chunk_end on upload.</li><li><code>mode</code> (string): &quot;write&quot; (truncate), &quot;append&quot;, or &quot;read&quot;.</li><li><code>path</code> (string): Relative path under interface dir (upload only).</li><li><code>params</code> (object): Opaque, interface-defined read parameters (read only); passed verbatim to the interface read() hook.</li></ul><p><code>chunk_done</code> fields:</p><ul><li><code>payload</code> (object): bytes_written (upload) or bytes_sent (read).</li></ul><p><code>widget_get</code> fields:</p><ul><li><code>id</code> (string): Correlation id.</li></ul><p><code>widget_state</code> fields:</p><ul><li><code>payload.state</code> (object): Full anywidget model state.</li></ul><p><code>widget_set</code> fields:</p><ul><li><code>changes</code> (object): Changed keys/values to apply.</li></ul><p><code>widget_change</code> fields:</p><ul><li><code>payload.changes</code> (object): Normalized changed keys/values.</li></ul><p><code>widget_msg</code> fields:</p><ul><li><code>content</code> (any): Message body (client‚Üíserver); reply in payload.</li></ul><p><strong>Binary flows</strong></p><p><em>upload</em>: Write opaque bytes to a path under the interface directory.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>client ‚Üí chunk_start {id, path, mode: write|append}</span></span>\n<span class="line"><span>client ‚Üí &lt;binary frame&gt; √óN</span></span>\n<span class="line"><span>client ‚Üí chunk_end {id}</span></span>\n<span class="line"><span>server ‚Üí chunk_done {path, bytes_written}</span></span></code></pre></div><p><em>read</em>: Stream the interface read() hook&#39;s bytes back, bounded.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>client ‚Üí chunk_start {id, mode: read, params}</span></span>\n<span class="line"><span>server ‚Üí &lt;binary frame&gt; √óN (bounded)</span></span>\n<span class="line"><span>server ‚Üí chunk_done {bytes_sent}</span></span>\n<span class="line"><span>server ‚Üí error {code: not_found}   # when missing</span></span></code></pre></div><h2 id="interface-hooks" tabindex="-1">Interface hooks <a class="header-anchor" href="#interface-hooks" aria-label="Permalink to &quot;Interface hooks&quot;">‚Äã</a></h2><p>Implemented by project interfaces:</p><h4 id="public-methods" tabindex="-1"><code>&lt;public methods&gt;</code> <a class="header-anchor" href="#public-methods" aria-label="Permalink to &quot;`&lt;public methods&gt;`&quot;">‚Äã</a></h4><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> method</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(self, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">args, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">kwargs) -&gt; Any </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Iterator</span></span></code></pre></div><p>Any non-underscore method is callable via <code>call</code>. Returning a generator streams as <code>stream</code> frames. Restrict with a class <code>__api_methods__</code> allowlist.</p><h4 id="read" tabindex="-1"><code>read</code> <a class="header-anchor" href="#read" aria-label="Permalink to &quot;`read`&quot;">‚Äã</a></h4><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(self, params: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dict</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) -&gt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bytes</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Iterable[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bytes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>Binary read hook for chunk_start mode=read. <code>params</code> is opaque to machinable. Raise machinable.errors.NotFound (or FileNotFoundError) to emit error{code:&#39;not_found&#39;}.</p><h4 id="emit" tabindex="-1"><code>emit</code> <a class="header-anchor" href="#emit" aria-label="Permalink to &quot;`emit`&quot;">‚Äã</a></h4><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">self</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.emit(payload: Any) </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">-&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> None</span></span></code></pre></div><p>Push an unsolicited <code>event</code> frame to a connected client during a call (e.g. progress).</p><h4 id="widget-state-widget-update-widget-message" tabindex="-1"><code>widget_state / widget_update / widget_message</code> <a class="header-anchor" href="#widget-state-widget-update-widget-message" aria-label="Permalink to &quot;`widget_state / widget_update / widget_message`&quot;">‚Äã</a></h4><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">machinable.Widget hooks (see the Widgets guide)</span></span></code></pre></div><p>A machinable.Widget ships an anywidget frontend (_esm/_css) and backs the model protocol: widget_state() (default: read-only config), widget_update() (rejects by default since config is immutable; keep state via save_file or mark), and widget_message(). Pushes via self.push_widget_change/message().</p><h4 id="local-directory" tabindex="-1"><code>local_directory</code> <a class="header-anchor" href="#local-directory" aria-label="Permalink to &quot;`local_directory`&quot;">‚Äã</a></h4><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">self</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.local_directory(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">append, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">False</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">-&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> str</span></span></code></pre></div><p>Working directory where uploaded chunks land and read() reads from. Machinable never parses the bytes.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">‚Äã</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Summary</th><th>Surfaces</th></tr></thead><tbody><tr><td><strong>remote_call</strong></td><td>Invoke any interface method over REST or WS, incl. streaming.</td><td><code>POST /v1/interfaces/call</code>; <code>ws: call/result/stream</code></td></tr><tr><td><strong>binary_upload</strong></td><td>Stream opaque bytes into an interface directory.</td><td>`ws: chunk_start(write</td></tr><tr><td><strong>binary_read</strong></td><td>Stream interface bytes back via its read() hook.</td><td><code>ws: chunk_start(read)</code></td></tr><tr><td><strong>config_search</strong></td><td>Query instances by config (operators), sort, and paginate.</td><td><code>POST /v1/interfaces/search</code></td></tr><tr><td><strong>create_by_id</strong></td><td>Content-addressed, idempotent create with a client id.</td><td><code>POST /v1/interfaces (uuid)</code>; <code>ws: connect(uuid)</code></td></tr><tr><td><strong>mutable_label</strong></td><td>Rename via a mutable label (config stays immutable).</td><td><code>PATCH /v1/interfaces/{uuid}/label</code></td></tr><tr><td><strong>creator_attribution</strong></td><td>Durable created_by metadata, queryable and reindex-preserved.</td><td><code>X-Machinable-User header</code>; <code>search/find created_by</code></td></tr><tr><td><strong>multi_project</strong></td><td>Serve many projects (and interpreters) from one gateway.</td><td><code>X-Machinable-Project</code>; <code>X-Machinable-Python</code></td></tr><tr><td><strong>source_edit</strong></td><td>Read/write/create/rename interface source (token-gated).</td><td><code>GET/PUT/DELETE /v1/source/{path}</code>; <code>POST /v1/source/move</code></td></tr><tr><td><strong>widgets</strong></td><td>Interfaces ship an anywidget frontend for notebook + web.</td><td>`GET /v1/project/{module}/widget/{esm</td></tr></tbody></table>',62)])])}const u=t(i,[["render",o]]);export{g as __pageData,u as default};
